package ru.memearena.tournament.infrastructure; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import ru.memearena.tournament.domain.*; import java.time.*; import java.util.*; public interface TournamentMatchRepository extends JpaRepository<TournamentMatch,UUID>{ List<TournamentMatch> findByTournamentIdAndRoundNumberOrderByMatchNumber(UUID t,int r); List<TournamentMatch> findByTournamentIdOrderByRoundNumberAscMatchNumberAsc(UUID t); boolean existsByTournamentIdAndRoundNumber(UUID t,int r); List<TournamentMatch> findByStatusAndEndsAtLessThanEqual(TournamentMatchStatus status, Instant now); }
